1	/**
2	 * Piece-session engine — quick (Animator-backed).
3	 *
4	 * Launches an anima session for a single piece writ. The prompt combines
5	 * the mandate body with the piece body and piece-specific execution
6	 * instructions.
7	 *
8	 * Custom collect():
9	 *   - On session completion → transitions the piece writ to 'completed'.
10	 *   - After collecting, checks for dynamically added child pieces of the
11	 *     mandate and grafts new piece-session engines for them.
12	 *
13	 * Note on failure: Spider's tryCollect() calls failEngine() directly for
14	 * failed/timeout sessions and never invokes collect(). Piece writ failure
15	 * relies on Clerk's parent/child cascade when the mandate reaches a
16	 * terminal state (stuck → child pieces get cancelled).
17	 *
18	 * Givens:
19	 *   - writ: WritDoc (the mandate writ)
20	 *   - piece: WritDoc (the piece writ for this task)
21	 *   - role: string
22	 *   - cwd: string (draft worktree path)
23	 */
24	
25	import { guild } from '@shardworks/nexus-core';
26	import type { EngineDesign, EngineRunContext } from '@shardworks/fabricator-apparatus';
27	import type { AnimatorApi, SessionDoc } from '@shardworks/animator-apparatus';
28	import type { StacksApi } from '@shardworks/stacks-apparatus';
29	import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
30	import type { SpiderCollectResult, RigTemplateEngine, RigDoc } from '../types.ts';
31	
32	/**
33	 * Classify a caught transition error. Returns true if the error message
34	 * indicates the writ is already in a terminal state (cancelled, completed,
35	 * failed) — in which case the failed transition is expected (the cascade or
36	 * another path beat us to it) and should be swallowed silently.
37	 *
38	 * Matches the wording produced by Clerk's `transition()` guard. Both the
39	 * pre-T2 and post-T2 error shapes are recognised so this classifier keeps
40	 * working across the writ-type-config refactor:
41	 *   pre-T2:  `Cannot transition writ "…" to "completed": phase is "cancelled", …`
42	 *   post-T2: `Cannot transition writ "…" from "cancelled" to "completed": legal transitions from "cancelled" are none (terminal state).`
43	 * Also tolerates future phrasing like "already terminal".
44	 */
45	function isAlreadyTerminalTransitionError(err: unknown): boolean {
46	  const message = err instanceof Error ? err.message : String(err);
47	  if (message.includes('already terminal')) return true;
48	  // Post-T2 strict-transition wording — `none (terminal state)` is emitted
49	  // exactly when the writ's current state is terminal and has no outbound
50	  // transitions, which is the race condition this guard is meant to swallow.
51	  if (message.includes('none (terminal state)')) return true;
52	  return (
53	    message.includes('phase is "cancelled"') ||
54	    message.includes('phase is "completed"') ||
55	    message.includes('phase is "failed"')
56	  );
57	}
58	
59	/**
60	 * Execution instructions for piece sessions. Focuses the anima on a single
61	 * task — no manifest traversal, commit-per-piece guidance.
62	 */
63	export const PIECE_EXECUTION_EPILOGUE = `
64	You are working on a single task from a larger mandate. Focus exclusively on this task.
65	
66	Instructions:
67	1. Complete the task described in the <task> element below the specification.
68	2. If the task has a <verify> command, run it after completing the work and confirm the <done> criterion is met.
69	3. The <files> element (if present) is the planner's predicted blast radius — useful for orientation, but verify scope independently.
70	4. If you discover additional work needed beyond this task, use the piece-add tool to create new tasks rather than doing them inline.
71	5. Commit all changes before ending your session.`;
72	
73	const pieceSessionEngine: EngineDesign = {
74	  id: 'piece-session',
75	
76	  async run(givens, context) {
77	    const animator = guild().apparatus<AnimatorApi>('animator');
78	    const mandateWrit = givens.writ as WritDoc;
79	    const piece = givens.piece as WritDoc;
80	
81	    if (!piece) {
82	      throw new Error('piece-session engine requires a "piece" given (WritDoc).');
83	    }
84	
85	    // Assemble prompt: mandate body + piece body + piece-specific epilogue
86	    const prompt = `${mandateWrit.body}\n\n---\n\n## Current Task\n\nMandate ID: ${mandateWrit.id}\n\n${piece.body}\n${PIECE_EXECUTION_EPILOGUE}`;
87	
88	    const handle = animator.summon({
89	      role: givens.role as string,
90	      prompt,
91	      cwd: givens.cwd as string,
92	      environment: { GIT_AUTHOR_EMAIL: `${mandateWrit.id}@nexus.local` },
93	      metadata: {
94	        engineId: context.engineId,
95	        writId: mandateWrit.id,
96	        pieceId: piece.id,
97	      },
98	    });
99	
100	    return { status: 'launched', sessionId: handle.sessionId };
101	  },
102	
103	  // Note: collect() is only called for completed sessions. Spider's tryCollect()
104	  // calls failEngine() directly for failed/timeout sessions, bypassing collect().
105	  async collect(sessionId: string, givens: Record<string, unknown>, context: EngineRunContext): Promise<SpiderCollectResult | unknown> {
106	    const stacks = guild().apparatus<StacksApi>('stacks');
107	    const clerk = guild().apparatus<ClerkApi>('clerk');
108	    const sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
109	
110	    const session = await sessionsBook.get(sessionId);
111	    const piece = givens.piece as WritDoc;
112	    const mandateWrit = givens.writ as WritDoc;
113	
114	    if (!piece || !mandateWrit) {
115	      // Fallback: return generic yields if givens are missing
116	      return {
117	        sessionId,
118	        sessionStatus: session?.status ?? 'completed',
119	      };
120	    }
121	
122	    // Completed session → mark piece completed.
123	    //
124	    // The transition may fail if the piece writ is already in a terminal
125	    // state (e.g. Clerk's downward cascade beat us to it after a sibling
126	    // failure). Classify the error: already-terminal is expected and silent;
127	    // anything else is a genuine bookkeeping failure that must be surfaced
128	    // via a warning so the race is visible in logs.
129	    try {
130	      await clerk.transition(piece.id, 'completed', {
131	        resolution: 'Task completed',
132	      });
133	    } catch (err) {
134	      if (!isAlreadyTerminalTransitionError(err)) {
135	        const message = err instanceof Error ? err.message : String(err);
136	        console.warn(
137	          `[piece-session] Unexpected error transitioning piece "${piece.id}" ` +
138	            `to completed: ${message}`,
139	        );
140	      }
141	      // Swallow — collect() must not throw. The current piece writ status
142	      // will be observed below and included in yields so downstream
143	      // consumers can see the actual outcome.
144	    }
145	
146	    // Re-read the piece writ after the transition attempt so yields reflect
147	    // the observed, authoritative phase — whether the transition succeeded
148	    // or was caught as already-terminal.
149	    let observedPiecePhase: WritDoc['phase'] | undefined;
150	    try {
151	      const observedPiece = await clerk.show(piece.id);
152	      observedPiecePhase = observedPiece.phase;
153	    } catch {
154	      // Writ lookup failure should not propagate out of collect(). Leave
155	      // observedPiecePhase undefined so yields omit the field entirely.
156	    }
157	
158	    // ── Dynamic piece pickup ──────────────────────────────────────────
159	    // Check for dynamically added child pieces that don't yet have engines.
160	    // Graft new piece-session engines for them so they run after this piece.
161	    const openChildren = await clerk.list({
162	      parentId: mandateWrit.id,
163	      type: 'piece',
164	      phase: 'open',
165	      limit: 50,
166	    });
167	
168	    // Determine which piece IDs already have engines in the rig
169	    const rigsBook = stacks.readBook<RigDoc>('spider', 'rigs');
170	    const rig = await rigsBook.get(context.rigId);
171	    const existingPieceIds = new Set<string>();
172	    if (rig) {
173	      for (const engine of rig.engines) {
174	        // Piece engines have a literal piece object in givensSpec
175	        const enginePiece = engine.givensSpec?.piece as WritDoc | undefined;
176	        if (enginePiece?.id) {
177	          existingPieceIds.add(enginePiece.id);
178	        }
179	      }
180	    }
181	
182	    // Filter to pieces that don't already have engines
183	    const newPieces = openChildren.filter(c => !existingPieceIds.has(c.id));
184	
185	    // Build graft entries for new pieces with sequential dependencies
186	    const graft: RigTemplateEngine[] = [];
187	    let previousEngineId = context.engineId; // chain starts after this engine
188	
189	    for (let i = 0; i < newPieces.length; i++) {
190	      const newPiece = newPieces[i]!;
191	      const engineId = `piece-${newPiece.id}`;
192	
193	      graft.push({
194	        id: engineId,
195	        designId: 'piece-session',
196	        upstream: [previousEngineId],
197	        givens: {
198	          writ: '${writ}',
199	          piece: newPiece, // literal WritDoc — survives resolveGivens/resolveYieldRefs
200	          role: givens.role as string,
201	          cwd: `\${yields.draft.path}`,
202	        },
203	      });
204	
205	      previousEngineId = engineId;
206	    }
207	
208	    const yields = {
209	      sessionId,
210	      sessionStatus: session?.status ?? 'completed',
211	      pieceId: piece.id,
212	      ...(observedPiecePhase !== undefined ? { pieceStatus: observedPiecePhase } : {}),
213	      ...(session?.output !== undefined ? { output: session.output } : {}),
214	      ...(newPieces.length > 0 ? { dynamicPieceIds: newPieces.map(p => p.id) } : {}),
215	    };
216	
217	    if (graft.length > 0) {
218	      // graftTail ensures engines downstream of this piece-session (e.g. the
219	      // next piece in the original chain, or seal via the original graftTail)
220	      // also wait for all dynamically added pieces to complete.
221	      const graftTail = `piece-${newPieces[newPieces.length - 1]!.id}`;
222	      return { yields, graft, graftTail } satisfies SpiderCollectResult;
223	    }
224	
225	    return yields;
226	  },
227	};
228	
229	export default pieceSessionEngine;
