#!/usr/bin/env python3
"""Correlate task count vs implement-session cost/tokens/duration, post-Apr-16."""
import os, re, glob, yaml
from datetime import datetime, timezone, date as dtdate
from pathlib import Path

COMMISSIONS = "/workspace/nexus-mk2/experiments/data/commissions"
APR16 = datetime(2026, 4, 16, tzinfo=timezone.utc)

def parse_task_count(body):
    m = re.search(r"<task-manifest>([\s\S]*?)</task-manifest>", body)
    if not m: return 0
    return len(re.findall(r"<task\b[^/]*?>", m.group(1)))

def coerce_dt(x):
    if x is None: return None
    if isinstance(x, datetime):
        return x if x.tzinfo else x.replace(tzinfo=timezone.utc)
    if isinstance(x, str):
        try:
            return datetime.fromisoformat(x.replace("Z","+00:00"))
        except Exception:
            return None
    return None

rows = []
for cdir in sorted(glob.glob(os.path.join(COMMISSIONS, "w-*"))):
    cmd = Path(cdir, "commission.md")
    if not cmd.exists(): continue
    tasks = parse_task_count(cmd.read_text(errors="replace"))
    if tasks == 0: continue
    sess_dir = Path(cdir, "sessions")
    if not sess_dir.exists(): continue
    best = None
    for sf in sorted(sess_dir.glob("*.yaml")):
        try:
            doc = yaml.safe_load(sf.open())
        except Exception:
            continue
        if not doc or doc.get("status") != "completed": continue
        cost = doc.get("cost_usd") or 0
        if best is None or cost > best.get("cost_usd", 0):
            best = doc
    if best is None: continue
    st = coerce_dt(best.get("started_at"))
    if st is None or st < APR16: continue
    tu = best.get("token_usage") or {}
    rows.append({
        "writ": os.path.basename(cdir)[:18],
        "session": (best.get("id") or "")[:20],
        "date": st.strftime("%Y-%m-%d"),
        "tasks": tasks,
        "cost": best.get("cost_usd", 0),
        "duration_s": (best.get("duration_ms",0) or 0)/1000,
        "output": tu.get("output_tokens", 0),
        "cache_read": tu.get("cache_read_tokens", 0),
        "cache_write": tu.get("cache_write_tokens", 0),
    })

rows.sort(key=lambda r:(r["date"], r["writ"]))
print(f"# n = {len(rows)} implement sessions (most-expensive-per-writ heuristic)")
print()
print(f"{'date':<11} {'writ':<20} {'tasks':>5} {'cost':>7} {'dur_s':>7} {'output':>8} {'cache_rd':>10} {'cache_wr':>9}")
for r in rows:
    print(f"{r['date']:<11} {r['writ']:<20} {r['tasks']:>5} ${r['cost']:>6.2f} {r['duration_s']:>7.0f} {r['output']:>8} {r['cache_read']:>10} {r['cache_write']:>9}")

def pearson(xs, ys):
    n = len(xs); mx = sum(xs)/n; my = sum(ys)/n
    num = sum((x-mx)*(y-my) for x,y in zip(xs,ys))
    denx = (sum((x-mx)**2 for x in xs))**0.5
    deny = (sum((y-my)**2 for y in ys))**0.5
    if denx==0 or deny==0: return 0
    return num/(denx*deny)

# Spearman: correlate ranks
def spearman(xs, ys):
    def ranks(vs):
        s = sorted(range(len(vs)), key=lambda i: vs[i])
        r = [0]*len(vs)
        for rank,i in enumerate(s, start=1):
            r[i] = rank
        # Handle ties via average rank
        from collections import defaultdict
        idx_by_v = defaultdict(list)
        for i,v in enumerate(vs):
            idx_by_v[v].append(i)
        for v, idxs in idx_by_v.items():
            avg = sum(r[i] for i in idxs)/len(idxs)
            for i in idxs: r[i] = avg
        return r
    return pearson(ranks(xs), ranks(ys))

print()
print("# Correlation with task count (Pearson / Spearman)")
tasks = [r["tasks"] for r in rows]
for k in ("cost","duration_s","output","cache_read","cache_write"):
    ys = [r[k] for r in rows]
    print(f"  tasks vs {k:<12}  pearson={pearson(tasks,ys):+.3f}  spearman={spearman(tasks,ys):+.3f}")

# Bucketed
print()
print("# Bucketed by task count")
print(f"{'tasks':>5} {'n':>4} {'avg_cost':>9} {'avg_dur_s':>10} {'avg_output':>11} {'avg_cache_rd':>13}")
by = {}
for r in rows: by.setdefault(r["tasks"], []).append(r)
for t in sorted(by):
    rs = by[t]; n = len(rs)
    print(f"{t:>5} {n:>4} ${sum(r['cost'] for r in rs)/n:>8.2f} {sum(r['duration_s'] for r in rs)/n:>10.0f} {sum(r['output'] for r in rs)/n:>11.0f} {sum(r['cache_read'] for r in rs)/n:>13.0f}")
PYEOF
python3 /tmp/task_correlation.py 2>&1

